import { getActiveQueryCount } from '../db/queries.js';
import { AnalyticsBar } from '../features/analytics/internal/AnalyticsBar.js';
import { useEffect, useState } from 'react';
export const Dashboard = () => {
  const [count, setCount] = useState(0);
  useEffect(() => {
    getActiveQueryCount().then(setCount);
  }, []);
  return (
    <div>
      <AnalyticsBar value={count} />
    </div>
  );
};
